import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import { EventBus } from '../../src/events/event-bus.js';
import { UserService, resetUserIdCounter } from '../../src/services/user.service.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter, resetEmailMessageIdCounter } from '../../src/adapters/email.adapter.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';
import type { NotificationCategory } from '../../src/models/user-preferences.js';
import { ALL_NOTIFICATION_CATEGORIES } from '../../src/models/user-preferences.js';

describe('PreferencesService', () => {
  let db: Database;
  let userRepo: UserRepository;
  let prefsRepo: PreferencesRepository;
  let eventBus: EventBus;
  let userService: UserService;
  let prefsService: PreferencesService;

  beforeEach(() => {
    db = new Database();
    userRepo = new UserRepository(db);
    prefsRepo = new PreferencesRepository(db);
    eventBus = new EventBus();
    userService = new UserService(userRepo, eventBus);
    prefsService = new PreferencesService(prefsRepo, userRepo);
    resetUserIdCounter();
    resetPreferencesIdCounter();
  });

  describe('getPreferences', () => {
    it('should return default preferences for user with no saved preferences', () => {
      const prefs = prefsService.getPreferences('user-0001');

      expect(prefs.userId).toBe('user-0001');
      expect(prefs.id).toBe('');
      expect(prefs.notifications.email.enabled).toBe(true);
      expect(prefs.notifications.email.frequency).toBe('immediate');
      expect(prefs.notifications.email.subscribedCategories).toEqual([
        'order_updates',
        'account_activity',
        'marketing',
      ]);
    });

    it('should return saved preferences when they exist', async () => {
      const user = await userService.createUser({
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
      });

      await prefsService.createPreferences({
        userId: user.id,
        email: { enabled: false },
      });

      const prefs = prefsService.getPreferences(user.id);
      expect(prefs.id).toBe('pref-0001');
      expect(prefs.notifications.email.enabled).toBe(false);
    });
  });

  describe('createPreferences', () => {
    it('should create preferences with defaults when no overrides given', async () => {
      const user = await userService.createUser({
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
      });

      const prefs = await prefsService.createPreferences({
        userId: user.id,
      });

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe(user.id);
      expect(prefs.notifications.email.enabled).toBe(true);
      expect(prefs.notifications.email.frequency).toBe('immediate');
      expect(prefs.notifications.email.subscribedCategories).toEqual(
        expect.arrayContaining(['order_updates', 'account_activity', 'marketing']),
      );
    });

    it('should create preferences with custom email settings', async () => {
      const user = await userService.createUser({
        name: 'Bob',
        email: 'bob@example.com',
        role: 'member',
      });

      const prefs = await prefsService.createPreferences({
        userId: user.id,
        email: {
          enabled: true,
          frequency: 'daily_digest',
          subscribedCategories: ['order_updates'],
        },
      });

      expect(prefs.notifications.email.frequency).toBe('daily_digest');
      expect(prefs.notifications.email.subscribedCategories).toEqual(['order_updates']);
    });

    it('should throw if user does not exist', async () => {
      await expect(
        prefsService.createPreferences({ userId: 'nonexistent' }),
      ).rejects.toThrow('User not found');
    });

    it('should throw if preferences already exist for user', async () => {
      const user = await userService.createUser({
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
      });

      await prefsService.createPreferences({ userId: user.id });

      await expect(
        prefsService.createPreferences({ userId: user.id }),
      ).rejects.toThrow('Preferences already exist');
    });

    it('should auto-increment preference IDs', async () => {
      const alice = await userService.createUser({
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
      });
      const bob = await userService.createUser({
        name: 'Bob',
        email: 'bob@example.com',
        role: 'member',
      });

      const p1 = await prefsService.createPreferences({ userId: alice.id });
      const p2 = await prefsService.createPreferences({ userId: bob.id });

      expect(p1.id).toBe('pref-0001');
      expect(p2.id).toBe('pref-0002');
    });
  });

  describe('updatePreferences', () => {
    it('should update email enabled flag', async () => {
      const user = await userService.createUser({
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
      });

      await prefsService.createPreferences({ userId: user.id });

      const updated = await prefsService.updatePreferences(user.id, {
        email: { enabled: false },
      });

      expect(updated.notifications.email.enabled).toBe(false);
      // Other fields should be unchanged
      expect(updated.notifications.email.frequency).toBe('immediate');
      expect(updated.notifications.email.subscribedCategories).toEqual(
        expect.arrayContaining(['order_updates', 'account_activity', 'marketing']),
      );
    });

    it('should update email frequency', async () => {
      const user = await userService.createUser({
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
      });

      await prefsService.createPreferences({ userId: user.id });

      const updated = await prefsService.updatePreferences(user.id, {
        email: { frequency: 'weekly_digest' },
      });

      expect(updated.notifications.email.frequency).toBe('weekly_digest');
    });

    it('should update subscribed categories', async () => {
      const user = await userService.createUser({
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
      });

      await prefsService.createPreferences({ userId: user.id });

      const updated = await prefsService.updatePreferences(user.id, {
        email: { subscribedCategories: ['order_updates'] },
      });

      expect(updated.notifications.email.subscribedCategories).toEqual(['order_updates']);
    });

    it('should throw if no preferences exist for user', async () => {
      await expect(
        prefsService.updatePreferences('nonexistent', {
          email: { enabled: false },
        }),
      ).rejects.toThrow('No preferences found');
    });

    it('should persist updates across reads', async () => {
      const user = await userService.createUser({
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
      });

      await prefsService.createPreferences({ userId: user.id });
      await prefsService.updatePreferences(user.id, {
        email: { enabled: false },
      });

      const prefs = prefsService.getPreferences(user.id);
      expect(prefs.notifications.email.enabled).toBe(false);
    });
  });

  describe('deletePreferences', () => {
    it('should delete existing preferences', async () => {
      const user = await userService.createUser({
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
      });

      await prefsService.createPreferences({ userId: user.id });

      expect(prefsService.deletePreferences(user.id)).toBe(true);

      // After deletion, getPreferences should return defaults
      const prefs = prefsService.getPreferences(user.id);
      expect(prefs.id).toBe('');
      expect(prefs.notifications.email.enabled).toBe(true);
    });

    it('should return false if no preferences exist', () => {
      expect(prefsService.deletePreferences('nonexistent')).toBe(false);
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true with default preferences (no saved prefs)', () => {
      expect(prefsService.shouldSendEmail('user-0001', 'order_updates')).toBe(true);
    });

    it('should return true when email is enabled and category is subscribed', async () => {
      const user = await userService.createUser({
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
      });

      await prefsService.createPreferences({
        userId: user.id,
        email: {
          enabled: true,
          frequency: 'immediate',
          subscribedCategories: ['order_updates'],
        },
      });

      expect(prefsService.shouldSendEmail(user.id, 'order_updates')).toBe(true);
    });

    it('should return false when email is disabled globally', async () => {
      const user = await userService.createUser({
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
      });

      await prefsService.createPreferences({
        userId: user.id,
        email: { enabled: false },
      });

      expect(prefsService.shouldSendEmail(user.id, 'order_updates')).toBe(false);
    });

    it('should return false when category is not subscribed', async () => {
      const user = await userService.createUser({
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
      });

      await prefsService.createPreferences({
        userId: user.id,
        email: {
          subscribedCategories: ['account_activity'],
        },
      });

      expect(prefsService.shouldSendEmail(user.id, 'order_updates')).toBe(false);
      expect(prefsService.shouldSendEmail(user.id, 'marketing')).toBe(false);
      expect(prefsService.shouldSendEmail(user.id, 'account_activity')).toBe(true);
    });

    it('should return false when frequency is not immediate', async () => {
      const user = await userService.createUser({
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
      });

      await prefsService.createPreferences({
        userId: user.id,
        email: { frequency: 'daily_digest' },
      });

      expect(prefsService.shouldSendEmail(user.id, 'order_updates')).toBe(false);
    });

    it('should return false for weekly digest frequency', async () => {
      const user = await userService.createUser({
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
      });

      await prefsService.createPreferences({
        userId: user.id,
        email: { frequency: 'weekly_digest' },
      });

      expect(prefsService.shouldSendEmail(user.id, 'order_updates')).toBe(false);
    });
  });

  describe('validateCategories', () => {
    it('should return true for valid categories', () => {
      expect(
        PreferencesService.validateCategories(['order_updates', 'marketing']),
      ).toBe(true);
    });

    it('should return true for all categories', () => {
      expect(
        PreferencesService.validateCategories([...ALL_NOTIFICATION_CATEGORIES]),
      ).toBe(true);
    });

    it('should return false for invalid categories', () => {
      expect(
        PreferencesService.validateCategories(['order_updates', 'invalid_category']),
      ).toBe(false);
    });

    it('should return true for empty array', () => {
      expect(PreferencesService.validateCategories([])).toBe(true);
    });
  });
});

describe('NotificationService with preferences', () => {
  let db: Database;
  let userRepo: UserRepository;
  let prefsRepo: PreferencesRepository;
  let eventBus: EventBus;
  let userService: UserService;
  let prefsService: PreferencesService;
  let notifService: NotificationService;
  let emailAdapter: EmailAdapter;

  beforeEach(() => {
    db = new Database();
    userRepo = new UserRepository(db);
    prefsRepo = new PreferencesRepository(db);
    eventBus = new EventBus();
    userService = new UserService(userRepo, eventBus);
    prefsService = new PreferencesService(prefsRepo, userRepo);
    notifService = new NotificationService(eventBus);
    emailAdapter = new EmailAdapter();
    notifService.registerAdapter(emailAdapter);
    notifService.setPreferencesService(prefsService);
    resetUserIdCounter();
    resetPreferencesIdCounter();
    resetNotificationIdCounter();
    resetEmailMessageIdCounter();
  });

  it('should send notification when user has default preferences (no saved prefs)', async () => {
    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-0001',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-0001',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(notifService.getNotificationCount()).toBe(1);
    expect(emailAdapter.getSentEmailCount()).toBe(1);
  });

  it('should skip notification when user has disabled email', async () => {
    const user = await userService.createUser({
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
    });

    await prefsService.createPreferences({
      userId: user.id,
      email: { enabled: false },
    });

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: user.id,
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: user.id,
        name: user.name,
        email: user.email,
        role: user.role,
        createdAt: user.createdAt,
        updatedAt: user.updatedAt,
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(notifService.getNotificationCount()).toBe(0);
    expect(emailAdapter.getSentEmailCount()).toBe(0);
  });

  it('should skip notification when user unsubscribed from order_updates', async () => {
    const user = await userService.createUser({
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
    });

    await prefsService.createPreferences({
      userId: user.id,
      email: {
        subscribedCategories: ['account_activity', 'marketing'],
      },
    });

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: user.id,
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: user.id,
        name: user.name,
        email: user.email,
        role: user.role,
        createdAt: user.createdAt,
        updatedAt: user.updatedAt,
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(notifService.getNotificationCount()).toBe(0);
    expect(emailAdapter.getSentEmailCount()).toBe(0);
  });

  it('should skip order status change when user has opted out', async () => {
    const user = await userService.createUser({
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
    });

    await prefsService.createPreferences({
      userId: user.id,
      email: { enabled: false },
    });

    const event: OrderStatusChangedEvent = {
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: user.id,
        items: [],
        total: 20,
        status: 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus: 'pending',
      newStatus: 'confirmed',
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(notifService.getNotificationCount()).toBe(0);
  });

  it('should send notification when no preferences service is set (backward compatible)', async () => {
    // Remove preferences service to test backward compatibility
    notifService.setPreferencesService(null);

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-0001',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-0001',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(notifService.getNotificationCount()).toBe(1);
    expect(emailAdapter.getSentEmailCount()).toBe(1);
  });

  it('should respect preferences when user switches from daily_digest', async () => {
    const user = await userService.createUser({
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
    });

    await prefsService.createPreferences({
      userId: user.id,
      email: { frequency: 'daily_digest' },
    });

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: user.id,
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: user.id,
        name: user.name,
        email: user.email,
        role: user.role,
        createdAt: user.createdAt,
        updatedAt: user.updatedAt,
      },
      timestamp: new Date(),
    };

    // Should be suppressed with daily_digest
    await eventBus.emit(event);
    expect(notifService.getNotificationCount()).toBe(0);

    // Update preferences to immediate
    await prefsService.updatePreferences(user.id, {
      email: { frequency: 'immediate' },
    });

    // Now should send
    await eventBus.emit(event);
    expect(notifService.getNotificationCount()).toBe(1);
  });
});
